#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> nums;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        nums.push_back(x);
    }

    int sum { 0 };
    int len { static_cast<int>(nums.size()) };
    for (int i = 0; i < len; ++i)
        sum += nums[i];

    std::cout << sum << '\n';
    return 0;
}

