solution_code:
#include <iostream>
#include <vector>

int countAbove(std::vector<int> v, int threshold)
{
    int count { 0 };
    int len { static_cast<int>(v.size()) };
    for (int i = 0; i < len; ++i)
    {
        if (v[i] > threshold)
            ++count;
    }
    return count;
}

int main()
{
    int n, threshold;
    std::cin >> n >> threshold;
    std::vector<int> data;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        data.push_back(x);
    }
    std::cout << countAbove(data, threshold) << '\n';
    return 0;
}
